def create_memory(size):
    """Create a memory block represented as a dictionary."""
    return {
        "slots": [0] * size,
        "size": size
    }


def store(memory, address, value):
    """Store a value at the given memory address."""
    if address < 0 or address >= memory["size"]:
        raise ValueError(f"Address {address} out of bounds (0-{memory['size'] - 1})")
    memory["slots"][address] = value
    return memory


def load(memory, address):
    """Load a value from the given memory address."""
    if address < 0 or address >= memory["size"]:
        raise ValueError(f"Address {address} out of bounds (0-{memory['size'] - 1})")
    return memory["slots"][address]


def memory_dump(memory):
    """Return a list of (address, value) tuples for non-zero slots."""
    return [(i, v) for i, v in enumerate(memory["slots"]) if v != 0]


# Test the memory simulator
mem = create_memory(8)
print(f"Created memory with {mem['size']} slots")

mem = store(mem, 0, 42)
mem = store(mem, 3, 99)
mem = store(mem, 7, 255)

print(f"Address 0: {load(mem, 0)}")
print(f"Address 3: {load(mem, 3)}")
print(f"Memory dump: {memory_dump(mem)}")

try:
    store(mem, 10, 1)
except ValueError as e:
    print(f"Error: {e}")

